mapper.select:
/* OrgPopupMapper.getHeadAgencyOrgnList */ SELECT OIM.ORGN_ID /* 조직 ID */ , OIM.ORGN_NM /* 조직명 */ , OIM.TYPE_CD /* 유형코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = OIM.TYPE_CD) AS TYPE_NM , OIM.ORGN_LVL_CD /* 조직레벨코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = OIM.ORGN_LVL_CD) AS ORGN_LVL_NM , OIM.APPL_STRT_DT /* 적용시작일자 */ , OIM.APPL_CMPLT_DT /* 적용종료일자 */ , OIM.KT_ORG_ID /* KT조직ID */ , OIM.OPEN_CRDT_LOAN_YN /* 개통여신여부 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0012' AND CD_VAL = OIM.OPEN_CRDT_LOAN_YN) AS OPEN_CRDT_LOAN_NM , OIM.OPEN_CRDT_LOAN_STRT_DT /* 개통여신시작일자 */ , DECODE(OIM.TAXBILL_YN, 'Y','Y','N') AS TAXBILL_YN /* 세금계산서발행여부 */ , DECODE(OIM.CMSN_PRVD_YN, 'Y','Y','N') AS CMSN_PRVD_YN /* 수수료지급여부 */ , DECODE(OIM.HNDST_INVTR_YN, 'Y','Y','N') AS HNDST_INVTR_YN /* 단말재고여부 */ , OIM.BIZ_TYPE_CD /* 사업자구분 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0007' AND CD_VAL = OIM.BIZ_TYPE_CD) AS BIZ_TYPE_NM , OIM.BIZ_REG_NUM /* 사업자등록번호 */ , OIM.CORP_REG_NUM /* 법인등록번호 */ , OIM.BIZ_CAT /* 업종 */ , OIM.BIZ_CON /* 업태 */ , OIM.RPRSEN_NM /* 대표자명 */ , OIM.TELNUM /* 전화번호 */ , OIM.FAX /* 팩스번호 */ , OIM.EMAIL /* 이메일 */ , OIM.ZIPCD /* 우편번호 */ , OIM.ADDR1 /* 주소1 */ , OIM.ADDR2 /* 주소2 */ , OIM.RESPN_PRSN_ID /* 담당자ID */ ,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_NM ,(SELECT TEL_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_NUM ,(SELECT MBLPHN_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_MBLPHN ,(SELECT EMAIL FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_EMAIL , OIM.HNDST_ORD_YN /* 단말주문여부 */ , OIM.ORGN_STAT_CD /* 조직상태코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = OIM.ORGN_STAT_CD) AS ORGN_STAT_NM , OIM.TMNT_DT /* 해지일자 */ , OIM.TYPE_DTL_CD /* 유형상세코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0004' AND CD_VAL = OIM.TYPE_DTL_CD) AS TYPE_DTL_NM , OIM.HGHR_ORGN_CD /* 상위조직코드 */ ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = OIM.HGHR_ORGN_CD) AS HGHR_ORGN_NM /* 상위조직코드명 */ , OIM.ORGN_GRD /* 조직등급 */ , OIM.CLOSE_YN /* 정리점여부 */ , OIM.LOGIS_CNTER_YN /* 물류센터여부 */ , OIM.TYPE_DTL_CD1 /* 유형상세코드1 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD1 AND USG_YN = 'Y') AS TYPE_DTL_CD_NM1 , OIM.TYPE_DTL_CD2 /* 유형상세코드2 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD2 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM2 , OIM.TYPE_DTL_CD3 /* 유형상세코드3 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD3 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM3 FROM ORG_ORGN_INFO_MST OIM WHERE OIM.TYPE_DTL_CD = 'Y' AND OIM.TYPE_CD != '30'
AND OIM.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND OIM.TYPE_CD = #{typeCd}
AND OIM.TYPE_CD >= 20
AND OIM.ORGN_LVL_CD = #{orgnLvlCd}
AND OIM.ORGN_LVL_CD >= 10
AND OIM.ORGN_STAT_CD = #{orgnStatCd}
START WITH ORGN_ID = CASE WHEN EXISTS (SELECT ORGN_ID FROM ORG_ORGN_INFO_MST WHERE LOGIS_CNTER_YN = 'Y' AND ORGN_ID = #{sessionUserOrgnId}) THEN '1' ELSE #{sessionUserOrgnId} END CONNECT BY PRIOR ORGN_ID = HGHR_ORGN_CD

/* OrgPopupMapper.getShopOrgnList */ SELECT T.ORGN_ID /* 조직 ID */ , T.ORGN_NM /* 조직명 */ , T.TYPE_CD /* 유형코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = T.TYPE_CD) AS TYPE_NM , T.ORGN_LVL_CD /* 조직레벨코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = T.ORGN_LVL_CD) AS ORGN_LVL_NM , T.APPL_STRT_DT /* 적용시작일자 */ , T.APPL_CMPLT_DT /* 적용종료일자 */ , T.OPEN_CRDT_LOAN_YN /* 개통여신여부 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0012' AND CD_VAL = T.OPEN_CRDT_LOAN_YN) AS OPEN_CRDT_LOAN_NM , T.OPEN_CRDT_LOAN_STRT_DT /* 개통여신시작일자 */ , DECODE(T.TAXBILL_YN, 'Y','Y','N') AS TAXBILL_YN /* 세금계산서발행여부 */ , DECODE(T.CMSN_PRVD_YN, 'Y','Y','N') AS CMSN_PRVD_YN /* 수수료지급여부 */ , DECODE(T.HNDST_INVTR_YN, 'Y','Y','N') AS HNDST_INVTR_YN /* 단말재고여부 */ , T.BIZ_TYPE_CD /* 사업자구분 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0007' AND CD_VAL = T.BIZ_TYPE_CD) AS BIZ_TYPE_NM , T.BIZ_REG_NUM /* 사업자등록번호 */ , T.CORP_REG_NUM /* 법인등록번호 */ , T.BIZ_CAT /* 업종 */ , T.BIZ_CON /* 업태 */ , T.RPRSEN_NM /* 대표자명 */ , T.TELNUM /* 전화번호 */ , T.FAX /* 팩스번호 */ , T.EMAIL /* 이메일 */ , T.ZIPCD /* 우편번호 */ , T.ADDR1 /* 주소1 */ , T.ADDR2 /* 주소2 */ , T.RESPN_PRSN_ID /* 담당자ID */ ,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = T.RESPN_PRSN_ID) AS RESPN_PRSN_NM ,(SELECT TEL_NUM FROM CMN_USR_MST WHERE USR_ID = T.RESPN_PRSN_ID) AS RESPN_PRSN_NUM ,(SELECT MBLPHN_NUM FROM CMN_USR_MST WHERE USR_ID = T.RESPN_PRSN_ID) AS RESPN_PRSN_MBLPHN ,(SELECT EMAIL FROM CMN_USR_MST WHERE USR_ID = T.RESPN_PRSN_ID) AS RESPN_PRSN_EMAIL , T.HNDST_ORD_YN /* 단말주문여부 */ , T.ORGN_STAT_CD /* 조직상태코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = T.ORGN_STAT_CD) AS ORGN_STAT_NM , T.TMNT_DT /* 해지일자 */ , T.TYPE_DTL_CD /* 유형상세코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0004' AND CD_VAL = T.TYPE_DTL_CD) AS TYPE_DTL_NM , T.HGHR_ORGN_CD /* 상위조직코드 */ ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = T.HGHR_ORGN_CD AND TYPE_CD = '20' AND ROWNUM = 1) AS HGHR_ORGN_NM /* 상위조직코드명 */ , T.ORGN_GRD /* 조직등급 */ , T.CLOSE_YN /* 정리점여부 */ , T.LOGIS_CNTER_YN /* 물류센터여부 */ , T.REG_ID /* 등록자ID */ , TO_CHAR(T.REG_DTTM, 'YYYYMMDD') AS REG_DTTM /*등록일시 */ , T.KT_ORG_ID /* KT조직ID */ , T.TYPE_DTL_CD1 /* 유형상세코드1 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = T.TYPE_DTL_CD1 AND USG_YN = 'Y') AS TYPE_DTL_CD_NM1 , T.TYPE_DTL_CD2 /* 유형상세코드2 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = T.TYPE_DTL_CD2 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM2 , T.TYPE_DTL_CD3 /* 유형상세코드3 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = T.TYPE_DTL_CD3 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM3 FROM ORG_ORGN_INFO_MST T, ORG_AGNCY_SHOP_REL R WHERE T.TYPE_DTL_CD = 'Y' AND T.TYPE_CD = '30' AND T.ORGN_ID = R.SHOP_ORGN_ID(+) AND T.HGHR_ORGN_CD = R.AGNCY_ORGN_ID(+) AND R.REL_END_DT = '99991231235959'
AND R.AGNCY_ORGN_ID = #{sessionUserOrgnId}
AND T.ORGN_ID = #{orgnId}
AND T.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND T.ORGN_STAT_CD = #{orgnStatCd}
ORDER BY T.ORGN_NM

/* OrgPopupMapper.getShopOrgnList */ SELECT ORGN_ID /* 조직 ID */ , ORGN_NM /* 조직명 */ , TYPE_CD /* 유형코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = TYPE_CD) AS TYPE_NM , ORGN_LVL_CD /* 조직레벨코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = ORGN_LVL_CD) AS ORGN_LVL_NM , APPL_STRT_DT /* 적용시작일자 */ , APPL_CMPLT_DT /* 적용종료일자 */ , OPEN_CRDT_LOAN_YN /* 개통여신여부 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0012' AND CD_VAL = OPEN_CRDT_LOAN_YN) AS OPEN_CRDT_LOAN_NM , OPEN_CRDT_LOAN_STRT_DT /* 개통여신시작일자 */ , DECODE(TAXBILL_YN, 'Y','Y','N') AS TAXBILL_YN /* 세금계산서발행여부 */ , DECODE(CMSN_PRVD_YN, 'Y','Y','N') AS CMSN_PRVD_YN /* 수수료지급여부 */ , DECODE(HNDST_INVTR_YN, 'Y','Y','N') AS HNDST_INVTR_YN /* 단말재고여부 */ , BIZ_TYPE_CD /* 사업자구분 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0007' AND CD_VAL = BIZ_TYPE_CD) AS BIZ_TYPE_NM , BIZ_REG_NUM /* 사업자등록번호 */ , CORP_REG_NUM /* 법인등록번호 */ , BIZ_CAT /* 업종 */ , BIZ_CON /* 업태 */ , RPRSEN_NM /* 대표자명 */ , TELNUM /* 전화번호 */ , FAX /* 팩스번호 */ , EMAIL /* 이메일 */ , ZIPCD /* 우편번호 */ , ADDR1 /* 주소1 */ , ADDR2 /* 주소2 */ , RESPN_PRSN_ID /* 담당자ID */ , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = RESPN_PRSN_ID) AS RESPN_PRSN_NM , (SELECT TEL_NUM FROM CMN_USR_MST WHERE USR_ID = RESPN_PRSN_ID) AS RESPN_PRSN_NUM , (SELECT MBLPHN_NUM FROM CMN_USR_MST WHERE USR_ID = RESPN_PRSN_ID) AS RESPN_PRSN_MBLPHN , (SELECT EMAIL FROM CMN_USR_MST WHERE USR_ID = RESPN_PRSN_ID) AS RESPN_PRSN_EMAIL , HNDST_ORD_YN /* 단말주문여부 */ , ORGN_STAT_CD /* 조직상태코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = ORGN_STAT_CD) AS ORGN_STAT_NM , TMNT_DT /* 해지일자 */ , TYPE_DTL_CD /* 유형상세코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0004' AND CD_VAL = TYPE_DTL_CD) AS TYPE_DTL_NM , HGHR_ORGN_CD /* 상위조직코드 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = A.HGHR_ORGN_CD AND TYPE_CD = '20' AND ROWNUM = 1) AS HGHR_ORGN_NM /* 상위조직코드명 */ , ORGN_GRD /* 조직등급 */ , CLOSE_YN /* 정리점여부 */ , LOGIS_CNTER_YN /* 물류센터여부 */ , REG_ID /* 등록자ID */ , TO_CHAR(REG_DTTM, 'YYYYMMDD') AS REG_DTTM /*등록일시 */ , KT_ORG_ID /* KT조직ID */ , TYPE_DTL_CD1 /* 유형상세코드1 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = TYPE_DTL_CD1 AND USG_YN = 'Y') AS TYPE_DTL_CD_NM1 , TYPE_DTL_CD2 /* 유형상세코드2 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = TYPE_DTL_CD2 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM2 , TYPE_DTL_CD3 /* 유형상세코드3 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = TYPE_DTL_CD3 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM3 FROM ORG_ORGN_INFO_MST A WHERE TYPE_CD = '30'
AND HGHR_ORGN_CD = #{sessionUserOrgnId}
AND ORGN_ID = #{orgnId}
AND ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND ORGN_STAT_CD = #{orgnStatCd}
AND ORGN_ID IN (SELECT DISTINCT ORGN_ID FROM CMN_USG_GRP_ASGN_MST A, CMN_USR_MST B WHERE A.USR_ID = B.USR_ID AND A.GRP_ID = 'G-PSCM2M' AND B.USG_YN <> 'N')
ORDER BY ORGN_NM

/* OrgPopupMapper.getSalesOrgnList */ SELECT ORG.ORGN_ID /* 조직 ID */ , ORG.ORGN_NM /* 조직명 */ , ORG.TYPE_CD /* 유형코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = ORG.TYPE_CD) AS TYPE_NM , HGHR_ORGN_CD /* 상위조직코드 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = ORG.HGHR_ORGN_CD AND ROWNUM = 1) AS HGHR_ORGN_NM /* 상위조직코드명 */ , ORG.APPL_STRT_DT /* 적용시작일자 */ , ORG.APPL_CMPLT_DT /* 적용종료일자 */ , ORG.ORGN_STAT_CD /* 조직상태코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = ORG.ORGN_STAT_CD) AS ORGN_STAT_NM FROM ORG_ORGN_INFO_MST ORG WHERE ORG.TYPE_CD != '10'
AND ORG.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND ORG.TYPE_CD = #{typeCd}
AND ORG.ORGN_STAT_CD = #{orgnStatCd}
ORDER BY ORGN_NM

/* userApprMapper.getHeadAgencyOrgnList */ SELECT OIM.ORGN_ID /* 조직 ID */ , OIM.ORGN_NM /* 조직명 */ , OIM.TYPE_CD /* 유형코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = OIM.TYPE_CD) AS TYPE_NM , OIM.ORGN_LVL_CD /* 조직레벨코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = OIM.ORGN_LVL_CD) AS ORGN_LVL_NM , OIM.APPL_STRT_DT /* 적용시작일자 */ , OIM.APPL_CMPLT_DT /* 적용종료일자 */ , OIM.KT_ORG_ID /* KT조직ID */ , OIM.OPEN_CRDT_LOAN_YN /* 개통여신여부 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0012' AND CD_VAL = OIM.OPEN_CRDT_LOAN_YN) AS OPEN_CRDT_LOAN_NM , OIM.OPEN_CRDT_LOAN_STRT_DT /* 개통여신시작일자 */ , DECODE(OIM.TAXBILL_YN, 'Y','Y','N') AS TAXBILL_YN /* 세금계산서발행여부 */ , DECODE(OIM.CMSN_PRVD_YN, 'Y','Y','N') AS CMSN_PRVD_YN /* 수수료지급여부 */ , DECODE(OIM.HNDST_INVTR_YN, 'Y','Y','N') AS HNDST_INVTR_YN /* 단말재고여부 */ , OIM.BIZ_TYPE_CD /* 사업자구분 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0007' AND CD_VAL = OIM.BIZ_TYPE_CD) AS BIZ_TYPE_NM , OIM.BIZ_REG_NUM /* 사업자등록번호 */ , OIM.CORP_REG_NUM /* 법인등록번호 */ , OIM.BIZ_CAT /* 업종 */ , OIM.BIZ_CON /* 업태 */ , OIM.RPRSEN_NM /* 대표자명 */ , OIM.TELNUM /* 전화번호 */ , OIM.FAX /* 팩스번호 */ , OIM.EMAIL /* 이메일 */ , OIM.ZIPCD /* 우편번호 */ , OIM.ADDR1 /* 주소1 */ , OIM.ADDR2 /* 주소2 */ , OIM.RESPN_PRSN_ID /* 담당자ID */ ,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_NM ,(SELECT TEL_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_NUM ,(SELECT MBLPHN_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_MBLPHN ,(SELECT EMAIL FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_EMAIL , OIM.HNDST_ORD_YN /* 단말주문여부 */ , OIM.ORGN_STAT_CD /* 조직상태코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = OIM.ORGN_STAT_CD) AS ORGN_STAT_NM , OIM.TMNT_DT /* 해지일자 */ , OIM.TYPE_DTL_CD /* 유형상세코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0004' AND CD_VAL = OIM.TYPE_DTL_CD) AS TYPE_DTL_NM , OIM.HGHR_ORGN_CD /* 상위조직코드 */ ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = OIM.HGHR_ORGN_CD) AS HGHR_ORGN_NM /* 상위조직코드명 */ , OIM.ORGN_GRD /* 조직등급 */ , OIM.CLOSE_YN /* 정리점여부 */ , OIM.LOGIS_CNTER_YN /* 물류센터여부 */ , OIM.TYPE_DTL_CD1 /* 유형상세코드1 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD1 AND USG_YN = 'Y') AS TYPE_DTL_CD_NM1 , OIM.TYPE_DTL_CD2 /* 유형상세코드2 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD2 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM2 , OIM.TYPE_DTL_CD3 /* 유형상세코드3 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD3 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM3 FROM ORG_ORGN_INFO_MST OIM WHERE OIM.TYPE_DTL_CD = 'Y' AND OIM.TYPE_CD != '10' AND ORGN_STAT_CD = '4' /* 가동 중인 대리점만 조회 */
AND OIM.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND OIM.TYPE_CD = #{typeCd}
AND OIM.TYPE_CD >= 20

/* OrgPopupMapper.getUsimOrgList */
SELECT OIM.ORGN_ID /* 조직 ID */ , OIM.ORGN_NM /* 조직명 */ , OIM.TYPE_CD /* 유형코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = OIM.TYPE_CD) AS TYPE_NM , OIM.ORGN_LVL_CD /* 조직레벨코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = OIM.ORGN_LVL_CD) AS ORGN_LVL_NM , OIM.APPL_STRT_DT /* 적용시작일자 */ , OIM.APPL_CMPLT_DT /* 적용종료일자 */ , OIM.KT_ORG_ID /* KT조직ID */ , OIM.OPEN_CRDT_LOAN_YN /* 개통여신여부 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0012' AND CD_VAL = OIM.OPEN_CRDT_LOAN_YN) AS OPEN_CRDT_LOAN_NM , OIM.OPEN_CRDT_LOAN_STRT_DT /* 개통여신시작일자 */ , DECODE(OIM.TAXBILL_YN, 'Y','Y','N') AS TAXBILL_YN /* 세금계산서발행여부 */ , DECODE(OIM.CMSN_PRVD_YN, 'Y','Y','N') AS CMSN_PRVD_YN /* 수수료지급여부 */ , DECODE(OIM.HNDST_INVTR_YN, 'Y','Y','N') AS HNDST_INVTR_YN /* 단말재고여부 */ , OIM.BIZ_TYPE_CD /* 사업자구분 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0007' AND CD_VAL = OIM.BIZ_TYPE_CD) AS BIZ_TYPE_NM , OIM.BIZ_REG_NUM /* 사업자등록번호 */ , OIM.CORP_REG_NUM /* 법인등록번호 */ , OIM.BIZ_CAT /* 업종 */ , OIM.BIZ_CON /* 업태 */ , OIM.RPRSEN_NM /* 대표자명 */ , OIM.TELNUM /* 전화번호 */ , OIM.FAX /* 팩스번호 */ , OIM.EMAIL /* 이메일 */ , OIM.ZIPCD /* 우편번호 */ , OIM.ADDR1 /* 주소1 */ , OIM.ADDR2 /* 주소2 */ , OIM.RESPN_PRSN_ID /* 담당자ID */ ,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_NM ,(SELECT TEL_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_NUM ,(SELECT MBLPHN_NUM FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_MBLPHN ,(SELECT EMAIL FROM CMN_USR_MST WHERE USR_ID = OIM.RESPN_PRSN_ID) AS RESPN_PRSN_EMAIL , OIM.HNDST_ORD_YN /* 단말주문여부 */ , OIM.ORGN_STAT_CD /* 조직상태코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = OIM.ORGN_STAT_CD) AS ORGN_STAT_NM , OIM.TMNT_DT /* 해지일자 */ , OIM.TYPE_DTL_CD /* 유형상세코드 */ ,(SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0004' AND CD_VAL = OIM.TYPE_DTL_CD) AS TYPE_DTL_NM , OIM.HGHR_ORGN_CD /* 상위조직코드 */ ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = OIM.HGHR_ORGN_CD) AS HGHR_ORGN_NM /* 상위조직코드명 */ , OIM.ORGN_GRD /* 조직등급 */ , OIM.CLOSE_YN /* 정리점여부 */ , OIM.LOGIS_CNTER_YN /* 물류센터여부 */ , OIM.TYPE_DTL_CD1 /* 유형상세코드1 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD1 AND USG_YN = 'Y') AS TYPE_DTL_CD_NM1 , OIM.TYPE_DTL_CD2 /* 유형상세코드2 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD2 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM2 , OIM.TYPE_DTL_CD3 /* 유형상세코드3 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = OIM.TYPE_DTL_CD3 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM3 FROM ORG_ORGN_INFO_MST OIM WHERE 1=1 AND OIM.ORGN_ID IN (SELECT DISTINCT ORGN_ID FROM MSP_PARTNER_USIM_MST)
AND OIM.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND OIM.ORGN_STAT_CD = #{orgnStatCd}
AND OIM.TYPE_CD = #{typeCd}
AND OIM.TYPE_CD >= 20
ORDER BY OIM.ORGN_NM

/* OrgPopupMapper.getKnoteOrgList */ SELECT ORGN_ID /* 조직 ID */ , ORGN_NM /* 조직명 */ , TYPE_CD /* 유형코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = TYPE_CD) AS TYPE_NM , ORGN_LVL_CD /* 조직레벨코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0006' AND CD_VAL = ORGN_LVL_CD) AS ORGN_LVL_NM , APPL_STRT_DT /* 적용시작일자 */ , APPL_CMPLT_DT /* 적용종료일자 */ , OPEN_CRDT_LOAN_YN /* 개통여신여부 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0012' AND CD_VAL = OPEN_CRDT_LOAN_YN) AS OPEN_CRDT_LOAN_NM , OPEN_CRDT_LOAN_STRT_DT /* 개통여신시작일자 */ , DECODE(TAXBILL_YN, 'Y','Y','N') AS TAXBILL_YN /* 세금계산서발행여부 */ , DECODE(CMSN_PRVD_YN, 'Y','Y','N') AS CMSN_PRVD_YN /* 수수료지급여부 */ , DECODE(HNDST_INVTR_YN, 'Y','Y','N') AS HNDST_INVTR_YN /* 단말재고여부 */ , BIZ_TYPE_CD /* 사업자구분 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0007' AND CD_VAL = BIZ_TYPE_CD) AS BIZ_TYPE_NM , BIZ_REG_NUM /* 사업자등록번호 */ , CORP_REG_NUM /* 법인등록번호 */ , BIZ_CAT /* 업종 */ , BIZ_CON /* 업태 */ , RPRSEN_NM /* 대표자명 */ , TELNUM /* 전화번호 */ , FAX /* 팩스번호 */ , EMAIL /* 이메일 */ , ZIPCD /* 우편번호 */ , ADDR1 /* 주소1 */ , ADDR2 /* 주소2 */ , RESPN_PRSN_ID /* 담당자ID */ , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = RESPN_PRSN_ID) AS RESPN_PRSN_NM , (SELECT TEL_NUM FROM CMN_USR_MST WHERE USR_ID = RESPN_PRSN_ID) AS RESPN_PRSN_NUM , (SELECT MBLPHN_NUM FROM CMN_USR_MST WHERE USR_ID = RESPN_PRSN_ID) AS RESPN_PRSN_MBLPHN , (SELECT EMAIL FROM CMN_USR_MST WHERE USR_ID = RESPN_PRSN_ID) AS RESPN_PRSN_EMAIL , HNDST_ORD_YN /* 단말주문여부 */ , ORGN_STAT_CD /* 조직상태코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0005' AND CD_VAL = ORGN_STAT_CD) AS ORGN_STAT_NM , TMNT_DT /* 해지일자 */ , TYPE_DTL_CD /* 유형상세코드 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0004' AND CD_VAL = TYPE_DTL_CD) AS TYPE_DTL_NM , HGHR_ORGN_CD /* 상위조직코드 */ , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = HGHR_ORGN_CD AND TYPE_CD = '20' AND ROWNUM = 1) AS HGHR_ORGN_NM /* 상위조직코드명 */ , ORGN_GRD /* 조직등급 */ , CLOSE_YN /* 정리점여부 */ , LOGIS_CNTER_YN /* 물류센터여부 */ , REG_ID /* 등록자ID */ , TO_CHAR(REG_DTTM, 'YYYYMMDD') AS REG_DTTM /*등록일시 */ , KT_ORG_ID /* KT조직ID */ , TYPE_DTL_CD1 /* 유형상세코드1 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = TYPE_DTL_CD1 AND USG_YN = 'Y') AS TYPE_DTL_CD_NM1 , TYPE_DTL_CD2 /* 유형상세코드2 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = TYPE_DTL_CD2 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM2 , TYPE_DTL_CD3 /* 유형상세코드3 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE CD_VAL = TYPE_DTL_CD3 AND USG_YN = 'Y' AND ETC1 IS NOT NULL) AS TYPE_DTL_CD_NM3 FROM ORG_ORGN_INFO_MST A , MDS_ORG_CPNT_INFO B WHERE A.ORGN_ID = B.CPNT_ID AND A.TYPE_CD != '10' AND A.KT_ORG_ID = (SELECT KT_ORG_ID FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = #{sessionUserOrgnId}) AND B.FILE_NM = (SELECT MAX(FILE_NM) FROM MDS_ORG_CPNT_INFO) AND B.SALE_TYPE_DIV_CD IN (SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'ORG0075' AND USG_YN = 'Y')
AND A.ORGN_ID = #{orgnId}
AND A.ORGN_NM LIKE '%'||#{orgnNm}||'%'
AND A.ORGN_STAT_CD = #{orgnStatCd}
ORDER BY A.TYPE_CD, A.ORGN_NM
